def check_path_exists_dfs(graph, start, target):
    if start == target:
        return True

    visited = set()

    def dfs(current_node):
        if current_node == target:
            return True

        visited.add(current_node)

        for neighbor in graph.get(current_node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
        return False

    if start not in graph:
        return False

    return dfs(start)
